 {"id":"asupersync-t59o","title":"[Codec] Implement Framed Transport","description":"# Framed Transport

## Overview
Combine AsyncRead/AsyncWrite with codecs for message-based I/O.

## Implementation

### Framed Type
```rust
use pin_project::pin_project;

/// Full-duplex framed transport
#[pin_project]
pub struct Framed<T, U> {
    #[pin]
    inner: FramedImpl<T, U>,
}

pub struct FramedImpl<T, U> {
    io: T,
    codec: U,
    read_buf: BytesMut,
    write_buf: BytesMut,
    eof: bool,
}

impl<T, U> Framed<T, U> {
    pub fn new(io: T, codec: U) -> Self {
        Self::with_capacity(io, codec, 8 * 1024)
    }

    pub fn with_capacity(io: T, codec: U, capacity: usize) -> Self {
        Self {
            inner: FramedImpl {
                io,
                codec,
                read_buf: BytesMut::with_capacity(capacity),
                write_buf: BytesMut::with_capacity(capacity),
                eof: false,
            },
        }
    }

    pub fn get_ref(&self) -> &T { &self.inner.io }
    pub fn get_mut(&mut self) -> &mut T { &mut self.inner.io }
    pub fn codec(&self) -> &U { &self.inner.codec }
    pub fn codec_mut(&mut self) -> &mut U { &mut self.inner.codec }
    pub fn read_buffer(&self) -> &BytesMut { &self.inner.read_buf }
    pub fn write_buffer(&self) -> &BytesMut { &self.inner.write_buf }

    pub fn into_inner(self) -> T { self.inner.io }
    pub fn into_parts(self) -> FramedParts<T, U> {
        FramedParts {
            io: self.inner.io,
            codec: self.inner.codec,
            read_buf: self.inner.read_buf,
            write_buf: self.inner.write_buf,
        }
    }
}

/// Parts for Framed reconstruction
pub struct FramedParts<T, U> {
    pub io: T,
    pub codec: U,
    pub read_buf: BytesMut,
    pub write_buf: BytesMut,
}
```

### Stream Implementation (Reading)
```rust
impl<T, U> Stream for Framed<T, U>
where
    T: AsyncRead + Unpin,
    U: Decoder,
{
    type Item = Result<U::Item, U::Error>;

    fn poll_next(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Option<Self::Item>> {
        let this = self.project();
        let inner = this.inner;

        loop {
            // Try to decode from existing buffer
            if let Some(item) = inner.codec.decode(&mut inner.read_buf)? {
                return Poll::Ready(Some(Ok(item)));
            }

            // Check for EOF
            if inner.eof {
                // Try decode_eof for final frame
                return match inner.codec.decode_eof(&mut inner.read_buf)? {
                    Some(item) => Poll::Ready(Some(Ok(item))),
                    None => Poll::Ready(None),
                };
            }

            // Read more data
            inner.read_buf.reserve(1024);
            let mut read_buf = ReadBuf::uninit(inner.read_buf.spare_capacity_mut());

            match Pin::new(&mut inner.io).poll_read(cx, &mut read_buf) {
                Poll::Ready(Ok(())) => {
                    let n = read_buf.filled().len();
                    if n == 0 {
                        inner.eof = true;
                    } else {
                        unsafe { inner.read_buf.advance_mut(n); }
                    }
                }
                Poll::Ready(Err(e)) => return Poll::Ready(Some(Err(e.into()))),
                Poll::Pending => return Poll::Pending,
            }
        }
    }
}
```

### Sink Implementation (Writing)
```rust
impl<T, I, U> Sink<I> for Framed<T, U>
where
    T: AsyncWrite + Unpin,
    U: Encoder<I>,
{
    type Error = U::Error;

    fn poll_ready(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Result<(), Self::Error>> {
        // Flush if buffer is too full
        let this = self.project();
        if this.inner.write_buf.len() >= 8192 {
            match self.poll_flush(cx) {
                Poll::Ready(Ok(())) => Poll::Ready(Ok(())),
                Poll::Ready(Err(e)) => Poll::Ready(Err(e)),
                Poll::Pending => Poll::Pending,
            }
        } else {
            Poll::Ready(Ok(()))
        }
    }

    fn start_send(self: Pin<&mut Self>, item: I) -> Result<(), Self::Error> {
        let this = self.project();
        this.inner.codec.encode(item, &mut this.inner.write_buf)
    }

    fn poll_flush(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Result<(), Self::Error>> {
        let this = self.project();
        let inner = this.inner;

        while !inner.write_buf.is_empty() {
            match Pin::new(&mut inner.io).poll_write(cx, &inner.write_buf) {
                Poll::Ready(Ok(n)) => {
                    inner.write_buf.advance(n);
                }
                Poll::Ready(Err(e)) => return Poll::Ready(Err(e.into())),
                Poll::Pending => return Poll::Pending,
            }
        }

        Pin::new(&mut inner.io).poll_flush(cx).map_err(Into::into)
    }

    fn poll_close(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Result<(), Self::Error>> {
        ready!(self.as_mut().poll_flush(cx))?;
        let this = self.project();
        Pin::new(&mut this.inner.io).poll_shutdown(cx).map_err(Into::into)
    }
}
```

### FramedRead and FramedWrite
```rust
/// Read-only framed transport
pub struct FramedRead<T, D> {
    inner: Framed<T, D>,
}

impl<T, D> FramedRead<T, D> {
    pub fn new(io: T, decoder: D) -> Self {
        Self { inner: Framed::new(io, decoder) }
    }
}

impl<T, D> Stream for FramedRead<T, D>
where
    T: AsyncRead + Unpin,
    D: Decoder,
{
    type Item = Result<D::Item, D::Error>;

    fn poll_next(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Option<Self::Item>> {
        Pin::new(&mut self.inner).poll_next(cx)
    }
}

/// Write-only framed transport
pub struct FramedWrite<T, E> {
    inner: Framed<T, E>,
}

impl<T, I, E> Sink<I> for FramedWrite<T, E>
where
    T: AsyncWrite + Unpin,
    E: Encoder<I>,
{
    type Error = E::Error;
    // ... delegate to inner
}
```

## Testing

### Unit Tests
```rust
#[tokio::test]
async fn test_framed_lines() {
    let (client, server) = duplex(1024);

    let mut client_framed = Framed::new(client, LinesCodec::new());
    let mut server_framed = Framed::new(server, LinesCodec::new());

    // Send from client
    client_framed.send("hello".to_string()).await.unwrap();
    client_framed.send("world".to_string()).await.unwrap();

    // Receive on server
    assert_eq!(server_framed.next().await.unwrap().unwrap(), "hello");
    assert_eq!(server_framed.next().await.unwrap().unwrap(), "world");
}

#[tokio::test]
async fn test_framed_bidirectional() {
    let (a, b) = duplex(1024);

    let mut a = Framed::new(a, LinesCodec::new());
    let mut b = Framed::new(b, LinesCodec::new());

    // Bidirectional communication
    a.send("ping".to_string()).await.unwrap();
    assert_eq!(b.next().await.unwrap().unwrap(), "ping");

    b.send("pong".to_string()).await.unwrap();
    assert_eq!(a.next().await.unwrap().unwrap(), "pong");
}
```

