## API Surface

### Collection API

```rust
impl RecoveryCollector {
    /// Collects symbols from replicas using quorum semantics.
    pub async fn collect_symbols(
        &mut self,
        object_id: ObjectId,
        replicas: &[ReplicaInfo],
    ) -> Result<Vec<CollectedSymbol>, Error> {
        self.progress.phase = RecoveryPhase::Collecting;

        // 1. Determine how many symbols we need
        let params = self.object_params.as_ref()
            .ok_or_else(|| Error::new(ErrorKind::Internal)
                .with_context("metadata not fetched"))?;

        let k = params.min_symbols_for_decode();
        self.progress.symbols_needed = k;

        // 2. Request symbols from replicas concurrently
        let mut futures = Vec::new();
        for replica in replicas {
            let fut = self.request_symbols_from(replica, object_id);
            futures.push(fut);
        }

        // 3. Collect responses with timeout
        let timeout = self.config.replica_timeout;
        let results = with_timeout(timeout, join_all(futures)).await?;

        // 4. Process results, deduplicating by ESI
        let mut seen_esi: HashSet<u32> = HashSet::new();
        for result in results {
            match result {
                Ok(symbols) => {
                    for symbol in symbols {
                        if !seen_esi.contains(&symbol.esi()) {
                            seen_esi.insert(symbol.esi());
                            self.collected.push(CollectedSymbol {
                                symbol,
                                source_replica: replica_id.clone(),
                                collected_at: Time::now(),
                                verified: false,
                            });
                            self.progress.symbols_collected += 1;
                        } else {
                            self.metrics.symbols_duplicate += 1;
                        }
                    }
                }
                Err(e) => {
                    self.metrics.requests_failed += 1;
                    // Log but continue - we may still get enough symbols
                }
            }
        }

        // 5. Check if we have enough
        if self.collected.len() >= k as usize {
            self.progress.phase = RecoveryPhase::Verifying;
            Ok(self.collected.clone())
        } else {
            Err(Error::insufficient_symbols(
                self.collected.len() as u32,
                k,
            ))
        }
    }
}
