### Orchestration API

```rust
impl RecoveryOrchestrator {
    /// Executes the complete recovery protocol.
    pub async fn recover(
        &mut self,
        trigger: RecoveryTrigger,
        replicas: &[ReplicaInfo],
    ) -> Result<RecoveryResult, Error> {
        let start = Instant::now();
        let region_id = trigger.region_id();

        // Log recovery start
        self.log_recovery_start(&trigger);

        // Phase 1: Fetch object metadata
        let object_id = self.fetch_current_object_id(region_id, replicas).await?;
        let params = self.collector.fetch_metadata(object_id, replicas).await?;

        // Update config with actual K value
        self.collector.config.min_symbols = params.min_symbols_for_decode();

        // Phase 2: Collect symbols with retries
        let mut last_error = None;
        for attempt in 1..=self.config.max_attempts {
            self.attempt = attempt;

            match self.collector.collect_symbols(object_id, replicas).await {
                Ok(symbols) => {
                    // Phase 3: Decode
                    for symbol in &symbols {
                        self.decoder.add_symbol(&symbol.symbol)?;
                    }

                    match self.decoder.decode_snapshot(&params) {
                        Ok(snapshot) => {
                            // Phase 4: Return result
                            return Ok(RecoveryResult {
                                snapshot,
                                symbols_used: symbols.len() as u32,
                                contributing_replicas: symbols
                                    .iter()
                                    .map(|s| s.source_replica.clone())
                                    .collect::<HashSet<_>>()
                                    .into_iter()
                                    .collect(),
                                duration: start.elapsed(),
                                attempt,
                                verified: self.decoder.config.verify_integrity,
                            });
                        }
                        Err(e) => {
                            last_error = Some(e);
                            self.decoder.reset();
                        }
                    }
                }
                Err(e) => {
                    last_error = Some(e);
                }
            }

            // Wait before retry (with exponential backoff)
            if attempt < self.config.max_attempts {
                let delay = self.config.retry_policy
                    .calculate_delay(attempt);
                sleep(delay).await;
            }
        }

        Err(last_error.unwrap_or_else(|| Error::new(ErrorKind::RecoveryFailed)
            .with_context("max recovery attempts exceeded")))
    }
}
