        LogEntry::new(LogLevel::Info, "recovery_complete")
            .with_field("region_id", result.snapshot.region_id.to_string())
            .with_field("symbols_used", result.symbols_used.to_string())
            .with_field("replicas_contributed", result.contributing_replicas.len().to_string())
            .with_field("duration_ms", result.duration.as_millis().to_string())
            .with_field("attempt", result.attempt.to_string())
            .with_field("verified", result.verified.to_string());
    }

    fn log_recovery_failed(&self, error: &Error) {
        LogEntry::new(LogLevel::Error, "recovery_failed")
            .with_field("error_kind", format!("{:?}", error.kind()))
            .with_field("attempt", self.attempt.to_string())
            .with_field("context", error.to_string());
    }
}

