        LogEntry::new(LogLevel::Debug, "symbol_collection_progress")
            .with_field("collected", self.progress.symbols_collected.to_string())
            .with_field("needed", self.progress.symbols_needed.to_string())
            .with_field("replicas_queried", self.progress.replicas_queried.to_string())
            .with_field("phase", format!("{:?}", self.progress.phase));
    }

    fn log_symbol_received(&self, symbol: &CollectedSymbol) {
        LogEntry::new(LogLevel::Trace, "symbol_received")
            .with_field("esi", symbol.symbol.esi().to_string())
            .with_field("source", symbol.source_replica.clone())
            .with_field("size", symbol.symbol.len().to_string());
    }
}

impl StateDecoder {
    fn log_decode_attempt(&self, params: &ObjectParams) {
        LogEntry::new(LogLevel::Debug, "decode_attempt")
            .with_field("object_id", params.object_id.to_string())
            .with_field("symbols_received", self.symbols_received().to_string())
            .with_field("symbols_needed", self.symbols_needed(params).to_string());
    }

    fn log_decode_result(&self, success: bool, duration: Duration) {
        let level = if success { LogLevel::Info } else { LogLevel::Warn };

        LogEntry::new(level, "decode_result")
            .with_field("success", success.to_string())
            .with_field("duration_ms", duration.as_millis().to_string());
    }
